import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';
import { HttpClientModule } from '@angular/common/http';
import { ReactiveFormsModule } from '@angular/forms';
import { RouterModule, Routes } from '@angular/router';

import { AppComponent } from './app.component';
import { PromptListComponent } from './prompt-list/prompt-list.component';
import { PromptDetailComponent } from './prompt-detail/prompt-detail.component';
import { PromptFormComponent } from './prompt-form/prompt-form.component';

const routes: Routes = [
  { path: '', redirectTo: 'prompts', pathMatch: 'full' },
  { path: 'prompts', component: PromptListComponent },
  { path: 'prompts/:id', component: PromptDetailComponent },
  { path: 'new', component: PromptFormComponent },
];

@NgModule({
  declarations: [
    AppComponent,
    PromptListComponent,
    PromptDetailComponent,
    PromptFormComponent,
  ],
  imports: [
    BrowserModule,
    HttpClientModule,
    ReactiveFormsModule,
    RouterModule.forRoot(routes),
  ],
  providers: [],
  bootstrap: [AppComponent]
})
export class AppModule { }
